#include <iostream>
#include <memory>
#include <string>
#include <vector>
#include <algorithm>

struct Task
{
    std::string name;
    int priority;
    Task(std::string n, int p) : name{ std::move(n) }, priority{ p } {}
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<Task>> source;
    for (int i{ 0 }; i < n; ++i)
    {
        std::string name{};
        int priority{};
        std::cin >> name >> priority;
        source.push_back(std::make_unique<Task>(std::move(name), priority));
    }

    std::stable_sort(source.begin(), source.end(),
        [](const std::unique_ptr<Task>& a, const std::unique_ptr<Task>& b)
        { return a->priority > b->priority; });

    std::vector<std::unique_ptr<Task>> dispatch;
    for (auto& task : source)
    {
        std::cout << "dispatch: " << task->name << '\n';
        dispatch.push_back(std::move(task));
    }

    int remaining{ 0 };
    for (const auto& task : source)
        if (task != nullptr)
            ++remaining;
    std::cout << "remaining: " << remaining << '\n';

    return 0;
}

