solution_code:
#include <iostream>
#include <memory>
#include <string>
#include <vector>

struct Resource
{
    std::string name;
    Resource(std::string n) : name{ std::move(n) }
    {
        std::cout << "create " << name << '\n';
    }
    ~Resource()
    {
        std::cout << "destroy " << name << '\n';
    }
};

int main()
{
    std::string name{};
    int q{};
    std::cin >> name >> q;

    std::vector<std::shared_ptr<Resource>> owners;
    owners.push_back(std::make_shared<Resource>(name));
    std::weak_ptr<Resource> watcher{ owners.front() };

    for (int i{ 0 }; i < q; ++i)
    {
        std::string cmd{};
        std::cin >> cmd;

        if (cmd == "acquire")
        {
            if (!owners.empty())
                owners.push_back(owners.back());
            std::cout << "owners: " << watcher.use_count() << '\n';
        }
        else if (cmd == "release")
        {
            if (!owners.empty())
                owners.pop_back();
            std::cout << "owners: " << watcher.use_count() << '\n';
        }
        else if (cmd == "check")
        {
            if (auto sp{ watcher.lock() })
                std::cout << "alive " << sp->name << '\n';
            else
                std::cout << "destroyed\n";
        }
    }

    return 0;
}
